import React from "react";
import { useState } from "react";
import useUserStore from './useUserStore'; 
import "bootstrap-icons/font/bootstrap-icons.css";

function TableRecent() {
  const [range, setRange] = useState({ from: 0, to: 5, pgNumber: 1 });
  const { from: start, to: end, pgNumber: pgNum } = range;
  const { userID, setUserID } = useUserStore();



  async function transactionHistoryGetter() {
  const res = await fetch("http://localhost:5001/api/getAllTransactions",{
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({id:userID}),
  });
  const result = await res.json();
  console.log(result);
  if (res.ok) {

    alert("Transactions pulled!");
  } else {
    alert("Something went wrong with pulling transactions.");
  }
}


const transactionHistory = transactionHistoryGetter();
console.log(transactionHistory);


  const numOfPgs = Math.ceil(transactionHistory.length / 5);

  function nextPg() {
    setRange((prev) => {
      return {
        from: prev.from + 5,
        to: prev.to + 5,
        pgNumber: prev.pgNumber + 1,
      };
    });
  }

  function prevPg() {
    setRange((prev) => {
      return {
        from: prev.from - 5,
        to: prev.to - 5,
        pgNumber: prev.pgNumber - 1,
      };
    });
  }

  return (
    <div className="table-responsive">
      <table className="table table-bordered table-striped">
        <thead className="table-dark">
          <tr>
            <th>Number</th>
            <th>Category</th>
            <th>Amount</th>
            <th>Date</th>
            <th>Description</th>
            <th>Modify</th>
          </tr>
        </thead>
        <tbody>
          {transactionHistory.slice(range.from, range.to).map((item, index) => (
            <tr key={index}>
              <td>{index}</td>
              <td>{item.category_name}</td>
              <td>{item.amount}</td>
              <td>{item.date}</td>
              <td>{item.description}</td>
              <td>
                <button>
                  <i className="bi bi-pencil-square"></i>
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* <div className="d-flex justify-content-center align-items-center gap-3">
        <button
          className="btn btn-secondary"
          onClick={prevPg}
          disabled={range.pgNumber === 1}
        >
          &lt;
        </button>

        <span>
          Page {range.pgNumber} of {numOfPgs}
        </span>

        <button
          className="btn btn-secondary"
          onClick={nextPg}
          disabled={range.pgNumber === numOfPgs}
        >
          &gt;
        </button>
      </div> */}
    </div>
  );
}

export default TableRecent;
